#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,s[N][3][3],t[3][3];

int cal(char c){
    return (c=='A'?0:(c=='T'?1:2));
}

void init(string a, string b){
    n=a.size();
    for(int i=1;i<=n;i++){
        for(int j=0;j<3;j++)
            for(int k=0;k<3;k++)
                s[i][j][k]=s[i-1][j][k];
        s[i][cal(a[i-1])][cal(b[i-1])]++;
    }
}

int get_distance(int x, int y){
    x++,y++;
    for(int i=0;i<3;i++)
        for(int j=0;j<3;j++)
            t[i][j]=s[y][i][j]-s[x-1][i][j];
    if(t[0][1]+t[0][2]!=t[1][0]+t[2][0] || t[1][0]+t[1][2]!=t[0][1]+t[2][1] || t[2][0]+t[2][1]!=t[0][2]+t[1][2])
        return -1;
    int sum=0;
    sum+=min(t[0][1],t[1][0]);
    sum+=min(t[1][2],t[2][1]);
    sum+=min(t[0][2],t[2][0]);
    return sum+2*(max(t[0][1],t[1][0])-min(t[0][1],t[1][0]));
}
